import React from "react";
import "../WelcomeMessage.css";

class WelcomeMessage extends React.Component {
  render() {
    return (
      <div className="welcome-chat-wrapper">
        <div className="welcome-chat-card">
          <div className="welcome-chat-title">
            👋 Welcome!
          </div>

          <div className="welcome-chat-body">
            Welcome to my personal page! This space is dedicated to <b>sharing my projects</b>, 
            <b>knowledge</b>, and <b>resources</b> in a way that is openly accessible to everyone. 
            The main <b>goal</b> of this page is <b></b>scientific outreach and creating a <b>publicly 
            available repository</b> of information and tools related to software development, 
            operating systems, programming languages, and technical resources.
          </div>

          <div className="welcome-chat-body">
            Here you will find code examples, guides, tutorials, repositories, and experiments 
            designed to help both beginners and experienced developers explore, learn, and 
            contribute to the shared knowledge base.
          </div>

          <div className="welcome-chat-footer">
            🚀 Ready to dive in? Start by navigating the menu above and explore the wealth 
            of resources, projects, and learning materials available — let curiosity be your guide!
          </div>
        </div>
      </div>
    );
  }
}

export default WelcomeMessage;
